import{_ as o,o as s,c as e,a0 as r}from"./chunks/framework.jwovEGr5.js";const a="/assets/shop-gui.A9N3807H.png",n="/assets/shop-detail.mQOGXFZF.png",_=JSON.parse('{"title":"🏪 Minecraft 箱子商店系統概覽","description":"","frontmatter":{},"headers":[],"relativePath":"Mc-Shop-System.md","filePath":"Mc-Shop-System.md"}'),i={name:"Mc-Shop-System.md"};function l(c,t,p,d,g,h){return s(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="🏪-minecraft-箱子商店系統概覽" tabindex="-1">🏪 Minecraft 箱子商店系統概覽 <a class="header-anchor" href="#🏪-minecraft-箱子商店系統概覽" aria-label="Permalink to &quot;🏪 Minecraft 箱子商店系統概覽&quot;">​</a></h1><p>箱子商店是伺服器的核心交易系統，讓玩家可以利用一個箱子與一個告示牌輕鬆擺攤賣貨或收購材料。</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>推薦您在遊戲中優先輸入 <strong><code>/shop</code></strong> 指令開啟箱子選單。在此選單中，您可以直觀地瀏覽所有玩家正在販售的商品，並滑鼠點選快速傳送，比起用指令更方便快捷！</p></div><p><img src="'+a+'" alt="遊戲內 /shop 箱子選單"></p><hr><h2 id="🪙-1-買家交易操作" tabindex="-1">🪙 1. 買家交易操作 <a class="header-anchor" href="#🪙-1-買家交易操作" aria-label="Permalink to &quot;🪙 1. 買家交易操作&quot;">​</a></h2><ul><li><p><strong>商品詳細資訊</strong>：當您指針懸停在商品上，或是看著商店告示牌時，系統會顯示該商店的評分與交易詳情。</p><p><img src="'+n+'" alt="商店詳細資訊"></p></li><li><p><strong>購買商品</strong>：對著商店的 <strong>告示牌【右鍵】</strong>。會跳出交易對話框，確認後即可購買。</p></li><li><p><strong>出售商品</strong>：對著商店的 <strong>告示牌【左鍵】</strong>。如果商店設有收購模式，您可以將物品賣給店主。</p></li></ul><hr><h2 id="📈-2-商店升級與管理" tabindex="-1">📈 2. 商店升級與管理 <a class="header-anchor" href="#📈-2-商店升級與管理" aria-label="Permalink to &quot;📈 2. 商店升級與管理&quot;">​</a></h2><ul><li><strong>商店升級 <code>/shop upgrade</code></strong>：每位玩家預設最多可建立 15 個商店。在遊戲內輸入此指令，消耗 <strong>$5,000 金幣</strong> 即可永久增加 1 個商店建立上限。</li><li><strong>商店更名 <code>/shop rename &lt;座標&gt; &lt;自訂名稱&gt;</code></strong>：花費 <strong>$5,000 金幣</strong> 將指定座標的商店更名，名稱會同步顯示在告示牌與網頁瀏覽器上。</li></ul>',10)])])}const u=o(i,[["render",l]]);export{_ as __pageData,u as default};
